// Parse JSON output จาก Gemini
try {
  let raw = $input.item.json.text || $input.item.json.output || '';
  // ลบ markdown code block ออก
  raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(raw);
  return { json: parsed };
} catch (e) {
  return {
    json: {
      action: 'reply',
      message: 'ขออภัยครับ ผมไม่สามารถประมวลผลคำสั่งได้ในตอนนี้ กรุณาลองใหม่อีกครั้ง',
      data: null
    }
  };
}

// สร้าง Response สำหรับ Quotation
// ส่งข้อมูลกลับตรงๆ ไปหน้าเว็บได้เลย
const payload = $input.item.json;
return {
  json: {
    action: 'quotation',
    message: payload.message || 'ร่างใบเสนอราคาให้คุณเรียบร้อยแล้วครับ ✅',
    data: payload.data || {}
  }
};

// กรองเฉพาะแถวที่ตรงกับชื่อที่ AI ระบุมา แล้วลบแค่ 1 แถวเท่านั้น
const allRows = $input.all().map(i => i.json);

// ดึงข้อมูล payload จาก Router (DB Operation)1
const routerData = $('Router (DB Operation)1').first().json;
const payload = routerData.data.payload;
const targetName = (payload.name || '').toString().trim().toLowerCase();
const targetId = (payload.id || '').toString().trim().toLowerCase();

if (!targetName && !targetId) {
  throw new Error('ไม่พบชื่อหรือรหัสที่ต้องการลบ');
}

// ค้นหาแถวที่ตรงกับชื่อหรือรหัส
let matchedRow = null;

// 1. ค้นหาจากรหัส (exact match)
if (targetId) {
  matchedRow = allRows.find(row => {
    const rowId = (row['รหัสลูกค้า/ผู้ขาย'] || '').toString().trim().toLowerCase();
    return rowId === targetId;
  });
}

// 2. ค้นจากชื่อ (exact match ก่อน แล้วค่อย includes)
if (!matchedRow && targetName) {
  // exact match ก่อน
  matchedRow = allRows.find(row => {
    const rowName = (row['ชื่อลูกค้า/ผู้ขาย'] || '').toString().trim().toLowerCase();
    return rowName === targetName;
  });
  // ถ้าไม่เจอ exact ให้ลอง includes
  if (!matchedRow) {
    matchedRow = allRows.find(row => {
      const rowName = (row['ชื่อลูกค้า/ผู้ขาย'] || '').toString().trim().toLowerCase();
      return rowName.includes(targetName) || targetName.includes(rowName);
    });
  }
}

if (!matchedRow) {
  const searchTerm = targetName || targetId;
  throw new Error('ไม่พบข้อมูล "' + searchTerm + '" ในระบบ กรุณาตรวจสอบชื่อหรือรหัสอีกครั้ง');
}

// row_number จาก Google Sheets (1-indexed) -> startIndex (0-indexed)
const deleteIndex = matchedRow.row_number; // ใช้ค่า row_number ได้เลย ไม่ต้องลบ 1 เพราะ n8n ใช้เป็นเลขแถวตรงๆ

return [{
  json: {
    row_number: deleteIndex,
    deleted_name: matchedRow['ชื่อลูกค้า/ผู้ขาย'] || matchedRow['รหัสลูกค้า/ผู้ขาย']
  }
}];

// ตัดสต็อก — อ่านค่าเดิม แล้วลบออก
// หมายเหตุ: ในงานจริงต้องอ่านค่าปัจจุบันก่อน แล้วค่อยคำนวณ
// นี่เป็น Logic ตัวอย่าง สามารถปรับให้ Read ก่อน Update ได้
const productName = $json.data.productName;
const amount = $json.data.amount;
return {
  json: {
    ...$json,
    deductInfo: {
      productName,
      amount,
      note: `ตัดสต็อก ${amount} ${$json.data.unit || 'ชิ้น'} เมื่อ ${new Date().toLocaleString('th-TH')}`
    }
  }
};

// รวม response จากทุก branch กลับมาเป็น format เดียวกัน
// และส่งกลับไปหน้าเว็บ React
const input = $input.item.json;

// ถ้ามาจาก Google Sheets node จะมี updatedRows หรือ appendedRow
const originalAction = input.action || 'database';
const originalMsg = input.message || 'ดำเนินการเรียบร้อยแล้วครับ ✅';

return {
  json: {
    action: originalAction,
    message: originalMsg,
    data: input.data || null
  }
};

// ตอบกลับข้อความทั่วไป
return {
  json: {
    action: 'reply',
    message: $input.item.json.message || 'มีอะไรให้ผมช่วยไหมครับ?',
    data: null
  }
};

const items = $input.all();
return items.map(item => {
  const body = item.json.body;
  const cleanData = { ...body.data };
  delete cleanData._rawRowNumber;
  return {
    json: {
      _action: body.action,
      _sheet: body.sheet,
      _idKey: body.idKey || 'id',
      ...cleanData
    }
  };
});

const payload = $items("Router (DB Operation)1")[0].json.data.payload;
const customers = $input.all().map(i => i.json);

const groupValue = (payload.type || '').toString().toLowerCase();
let firstChar = 'C'; 
if (groupValue.includes('vender') || groupValue.includes('vendor')) {
  firstChar = 'P';
} else if (groupValue.includes('credit')) {
  firstChar = 'C';
}

const nameValue = (payload.name || '').toString();

const getEnglishInitial = (text) => {
  let cleanText = text.replace(/^(บริษัท|บจก\.|บมจ\.|หจก\.|ห้างหุ้นส่วนจำกัด|ร้าน)\s*/g, '').trim();
  if (!cleanText) cleanText = text;

  const engMatch = cleanText.match(/[a-zA-Z]/);
  if (engMatch) return engMatch[0].toUpperCase();

  const consonantMatch = cleanText.match(/[ก-ฮ]/);
  if (consonantMatch) {
    const map = {
      'ก':'K','ข':'K','ฃ':'K','ค':'K','ฅ':'K','ฆ':'K','ง':'N','จ':'J',
      'ฉ':'C','ช':'C','ซ':'S','ฌ':'C','ญ':'Y','ฎ':'D','ฏ':'T','ฐ':'T',
      'ฑ':'T','ฒ':'T','ณ':'N','ด':'D','ต':'T','ถ':'T','ท':'T','ธ':'T',
      'น':'N','บ':'B','ป':'P','ผ':'P','ฝ':'F','พ':'P','ฟ':'F','ภ':'P',
      'ม':'M','ย':'Y','ร':'R','ล':'L','ว':'W','ศ':'S','ษ':'S','ส':'S',
      'ห':'H','ฬ':'L','อ':'O','ฮ':'H'
    };
    return map[consonantMatch[0]] || 'X';
  }
  return 'X';
};

const secondChar = getEnglishInitial(nameValue);
const prefix = `${firstChar}${secondChar}`;
let maxNum = 0;

customers.forEach(row => {
  const existingId = (row['รหัสลูกค้า/ผู้ขาย'] || row['id'] || '').toString();
  if (existingId.startsWith(prefix)) {
    const numPart = existingId.substring(2);
    const num = parseInt(numPart, 10);
    if (!isNaN(num) && num > maxNum) {
      maxNum = num;
    }
  }
});

const nextNum = (maxNum + 1).toString().padStart(3, '0');
const finalId = `${prefix}${nextNum}`;

payload.id = finalId;

return [{
  json: {
    data: {
      payload: payload,
      table: "customers",
      operation: "add"
    }
  }
}];
